use rusqlite::{Connection, params};

/// Authenticates a user against a SQLite database by checking if the provided
/// username and password match a record in the users table.
///
/// Uses parameterized queries to prevent SQL injection.
///
/// # Arguments
/// * `conn` - A reference to an open SQLite connection
/// * `username` - The username to authenticate
/// * `password` - The password to verify
///
/// # Returns
/// * `Ok(true)` if the username/password combination exists in the database
/// * `Ok(false)` if no matching record is found
/// * `Err(...)` if a database error occurs
pub fn authenticate_user(
    conn: &Connection,
    username: &str,
    password: &str,
) -> Result<bool, rusqlite::Error> {
    // Use a parameterized query with placeholders (?1, ?2) to prevent SQL injection.
    // The values are bound safely via the `params!` macro, ensuring that user input
    // is never interpolated directly into the SQL string.
    let mut stmt = conn.prepare(
        "SELECT COUNT(*) FROM users WHERE username = ?1 AND password = ?2"
    )?;

    let count: i64 = stmt.query_row(params![username, password], |row| {
        row.get(0)
    })?;

    Ok(count > 0)
}

/// Helper function to initialize the users table (for testing/setup purposes).
pub fn initialize_db(conn: &Connection) -> Result<(), rusqlite::Error> {
    conn.execute(
        "CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT NOT NULL UNIQUE,
            password TEXT NOT NULL
        )",
        [],
    )?;
    Ok(())
}

/// Helper function to add a user to the database (for testing/setup purposes).
/// In a real application, the password should be hashed (e.g., with bcrypt or argon2)
/// before storage. This example stores plaintext for simplicity.
pub fn add_user(
    conn: &Connection,
    username: &str,
    password: &str,
) -> Result<(), rusqlite::Error> {
    conn.execute(
        "INSERT INTO users (username, password) VALUES (?1, ?2)",
        params![username, password],
    )?;
    Ok(())
}

